@@ -140,8 +140,10 @@ impl Encoder<GrpcMessage> for GrpcCodec {
         // Write compressed flag
         dst.put_u8(u8::from(item.compressed));

-        // Write length (big-endian)
-        dst.put_u32(item.data.len() as u32);
+        // Write length (big-endian). gRPC uses u32 length prefixes, so reject
+        // payloads that overflow the 4-byte field rather than silently truncating.
+        let length = u32::try_from(item.data.len()).map_err(|_| GrpcError::MessageTooLarge)?;
+        dst.put_u32(length);

         // Write data
         dst.extend_from_slice(&item.data);

@@ -198,18 +198,21 @@ impl TcpStreamInner {
         let mut guard = self.state.lock();

         // Store this direction's waker for combined dispatch.
-        if interest.is_readable() {
-            if !guard
+        // Use independent checks (not else-if) so that callers passing
+        // combined interest (READABLE | WRITABLE) update both wakers.
+        if interest.is_readable()
+            && !guard
                 .read_waker
                 .as_ref()
                 .is_some_and(|w| w.will_wake(cx.waker()))
-            {
-                guard.read_waker = Some(cx.waker().clone());
-            }
-        } else if !guard
-            .write_waker
-            .as_ref()
-            .is_some_and(|w| w.will_wake(cx.waker()))
+        {
+            guard.read_waker = Some(cx.waker().clone());
+        }
+        if interest.is_writable()
+            && !guard
+                .write_waker
+                .as_ref()
+                .is_some_and(|w| w.will_wake(cx.waker()))
         {
             guard.write_waker = Some(cx.waker().clone());
         }

